import * as React from "react"
import { useState, useEffect, useRef } from "react"
import { graphql } from "gatsby"
// import { StaticImage } from 'gatsby-plugin-image'

import Bio from "../components/bio"
import Layout from "../components/layout"
import Seo from "../components/seo"
import Categories from "../components/custom/category-component"
import PostList from "../components/custom/postList"

const BlogIndex = ({ data, location }) => {
  const [reactingClassName, setReactingClassName] = useState({
    categoryName: "category-comp-absolute",
    inputName: "search-comp-absolute",
  })
  const [searchText, setSearchText] = useState()
  const [postList, setPostList] = useState([])

  const rawData = data.allMarkdownRemark.nodes
  const siteTitle = data.site.siteMetadata?.title || `Title`
  const viewport = useRef(null)
  const target = useRef(null)

  const getInputValue = ({ target: { value } }) => {
    setSearchText(value)
  }

  /* 
  
  22.01.09.
  검색 이후 title이 result로 고정되는 버그 존재 
  검색 이후에는 postList에 항상 값이 들어가 있어서 이런 오류가 발생하는 듯하다.
  
  */

  const searchPost = ({ key }) => {
    if (key.toLowerCase() !== "enter") {
      return
    }

    const result = rawData.filter(el =>
      el.frontmatter.title.toLowerCase().includes(searchText)
    )

    setPostList(result)

    if (!result.length) {
      return alert("검색어를 입력해주세요.")
    }
  }

  useEffect(() => {
    const handleIntersection = entires => {
      entires.forEach(entry => {
        if (!entry.isIntersecting) {
          setReactingClassName({
            categoryName: "category-comp-fixed",
            inputName: "search-comp-fixed",
          })
        } else {
          setReactingClassName({
            categoryName: "category-comp-absolute",
            inputName: "search-comp-absolute",
          })
        }
      })
    }

    const io = new IntersectionObserver(handleIntersection)

    io.observe(target.current)

    return () => io.disconnect()
  }, [])

  if (rawData.length === 0) {
    return (
      <Layout location={location} title={siteTitle}>
        <Seo title="All posts" />
        <Bio />
        <p>
          No blog posts found. Add markdown posts to "content/blog" (or the
          directory you specified for the "gatsby-source-filesystem" plugin in
          gatsby-config.js).
        </p>
      </Layout>
    )
  }

  return (
    <div className="custom-wrapper" ref={viewport}>
      <Layout location={location} title={siteTitle}>
        <Seo title="All posts" />
        <Bio />
        <div className="category-wrapper" ref={target}>
          {/* 1222 검색 이미지 넣기 */}
          <input
            type="text"
            className={reactingClassName.inputName}
            onChange={getInputValue}
            onKeyDown={searchPost}
          />
          {/* <div className="category-comp-icon" >
            <StaticImage src="../images/hamburger.png" width={20} />
          </div> */}
          <Categories name={reactingClassName.categoryName} />
        </div>

        {!postList.length ? (
          <PostList title={"Post"} posts={rawData} />
        ) : (
          <PostList title={"Result"} posts={postList} />
        )}
      </Layout>
    </div>
  )
}

export default BlogIndex

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      nodes {
        excerpt(pruneLength: 90, truncate: true)
        fields {
          slug
        }
        frontmatter {
          date(formatString: "MMMM DD, YYYY")
          title
          description
        }
      }
    }
  }
`
